        b_ab *= warmth_factor;
    }

    // LAB → RGB
    float l_out  = fminf(fmaxf(l_norm * 100.0f, 0.0f), 100.0f);
    float a_out  = fminf(fmaxf(a_ab,  -128.0f), 127.0f);
